script.text:
      &JavascriptReportInit;

function load$GridCalcCost(g) {
  g._$l = [];
  g._$k = [];
  g._$i = g._getColumnOrder('stt_rec');
  g._$t = g._getColumnOrder('&Tag;');
  g._$s = g._getColumnOrder('tinh_trang%l');
  g._$u = g._getColumnOrder('nguoi_tinh');
  g._$d = g._getColumnOrder('ngay');
  g.add_commandEvent(on$GridCalcCostReport$ExecuteCommand);
  g.add_onResponseComplete(on$GridCalcCostReport$ResponseComplete);
  g.add_onRender(on$GridReport$Render);
}

/* <flatten type="Javascript"> */
function scatter$Grid(g) {fill$Grid(g, true);}
function dispose$GridCalcCost(g) {
  try {g.remove_commandEvent(on$GridCalcCostReport$ExecuteCommand);} catch (ex) {}
  try {g.remove_onResponseComplete(on$GridCalcCostReport$ResponseComplete);} catch (ex) {}
  try {g.remove_onRender(on$GridReport$Render);} catch (ex) {}
  g._$k = g._$i = g._$t = g._$s = g._$u = g._$d = g._$l = null;
}
function on$GridCalcCostReport$ExecuteCommand(sender, e) {
  var action = e.type.Action, g = sender;
  switch (action) {
    case 'BeforeRemoveRow':
      var k = Array.indexOf(g._$k, g._getItemValue(g._activeRow, g._getColumnOrder('stt_rec')));
      if (k != -1) Array.removeAt(g._$k, k);
      break;
    case 'Calculate':
      var s = g._$k.join(',')
      if (isCheck$Grid(g)) g.request(g, 'Order', 'Order', [['s', 'String', s], ['ky', 'Decimal', g._period], ['nam', 'Decimal', g._year]]);
      break;
    case 'Register':
    case 'Cancel':
      if (g._$l.length > 0) break;
      var s = g._$k.join(',')
      if (isCheck$Grid(g)) g.request(g, action, action, [['s', 'String', s], ['ky', 'Decimal', g._period], ['nam', 'Decimal', g._year]]);
      break;
    default:
      break;
  }
}
function on$GridCalcCostReport$ResponseComplete(sender, e) {
  var g = e.object, context = e.type.Context, result = e.type.Result, o = e.type.Object, id = g.get_id(), v = g._language == 'v';
  var m1 = v ? 'Chương trình đã thực hiện xong.' : 'The process was completed successfully.';
  var s = v ? 'Đặt lịch': 'Schedule';
  if (context == 'Cancel') s = '';
  switch (context) {
    case 'Register':
    case 'Cancel':
      if (result[0].Value == '1') {
        $message.show(result[1].Value, String.format('$find(\'{0}\')._focusWhenTabChanged();', id));
      } else {
        g._$k = [];
        $message.show(m1, String.format('$find(\'{0}\')._focusWhenTabChanged();', id));
        changeStatusGrid(g, null, 0, s, '', '');
      }
      break;
    case 'Order':
      if (result[0].Value == '1') {
        $message.show(result[1].Value, String.format('$find(\'{0}\')._focusWhenTabChanged();', id));
      } else {
        g._$l = result;
        if (g._$l.length > 0) g.request(g, 'Calculate', 'Calculate', [['stt_rec', 'String', g._$l[0][1]], ['ky', 'Decimal', g._period], ['nam', 'Decimal', g._year], ['step', 'Decimal', 1]]);
      }
      break;
    case 'Calculate':
      var i = result[0].Value;
      changeStatusGrid(g, g._$l[i-2][1], 2, '', result[1].Value, result[2].Value);
      if (i <= g._$l.length) setTimeout(function() {g.request(g, 'Calculate', 'Calculate', [['stt_rec', 'String', g._$l[i-1][1]], ['ky', 'Decimal', g._period], ['nam', 'Decimal', g._year], ['step', 'Decimal', i]]);}, 1000);
      else {
        g._$k = [];
        g._$l = [];
        $message.show(m1, String.format('$find(\'{0}\')._focusWhenTabChanged();', id));
      }
      break;
    default:
      break;
  }
}
function on$GridReport$Render(sender, eventArgs) {
  var g = eventArgs.grid;
  if (g._hiddenFields) {
    var a = g._hiddenFields, h = '';
    for (var i = 0; i < a.length; i++) {
      setGridHiddenFields(g, a[i].Fields, a[i].Value);
      if (a[i].Value) h += (h == '' ? '' : ',') + a[i].Fields;
    }
    g._externalHiddenFields = h;
  }
}

function changeStatusGrid(g, k, t, v, u, d) {
  for (var i = 1; i <= g._rowCount; i ++) {
    if (g._getItemValue(i, g._$i) == k || !k) {
      if(g._getItemValue(i, g._$t)) {
        g._setItemValue(i, g._$s, v);
        if (t) {
          g._setItemValue(i, g._$u, u);
          g._setItemValue(i, g._$d, d);
        }
      }
      g._setItemValue(i, g._$t, false);
    }
  }
}
function setGridHiddenFields(g, c, v) {
  var a = c.split(',');
  for (var i = 0; i < a.length; i++) {
    g._setColumnVisible(g._getColumnOrder($func.trim(a[i])), !v);
  }
}
/* </flatten> */
      &ScriptTag;

action.text:
        &CommandCheckLockedDate;

select '' as array$, stt_rec from xdmtgt where [dbo].[ff_Inlist] (stt_rec, @s) = 1 order by ma_dvcs, buoc_tinh
return

&CommandCheckLockedDate;
declare @count int, @i int, @stt_rec char(13) select @count = dbo.FastBusiness$Function$GetWordCount (@s, ',') select @i = 1
while @i <= @count begin select @stt_rec = dbo.[FastBusiness$Function$GetWordNum](@s, @i, ',') if not exists (select 1 from xcttgt where ky = @ky and nam = @nam and stt_rec = @stt_rec) begin insert into xcttgt (ky, nam, stt_rec, status, user_id0, datetime0) select @ky, @nam, @stt_rec, '1', @@userID, getdate() end else begin update xcttgt set status = '1', user_id0 = @@userID, datetime0 = getdate() where ky = @ky and nam = @nam and stt_rec = @stt_rec end select @i = @i +1 end select 0 as error return
